SELECT audit_id, actor_id, action, entity_type, entity_id, created_at
FROM audit_log
WHERE created_at::date = #{date}
AND actor_id = #{actorId}
AND entity_type = #{entityType}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM audit_log
WHERE created_at::date = #{date}
AND actor_id = #{actorId}
AND entity_type = #{entityType}
